template:
const std = @import("std");

pub const Flag = [[SLOT union_kw]] {
    boolean: bool,
    string: []const u8,
    integer: i64,
};

pub fn parseFlag(input: []const u8) Flag {
    const equals_idx = [[SLOT index_call]] orelse {
        return [[SLOT bool_default]];
    };

    const value = input[equals_idx + 1..];

    const parsed = [[SLOT parse_call]] catch {
        return .{ .string = value };
    };

    return .{ .integer = parsed };
}
